for (const item of $input.all()) {
  // 1. Acessa o texto SRT bruto do item.json.srt (ou o nome do campo que contém a string limpa)
  // AJUSTE: Mude 'item.json.srt' se o nome do campo for diferente.
  let srtText = item.json.srt;

  // 2. Processo de Normalização de Quebras de Linha e Caracteres de Escape:
  // Este bloco é crucial se a string ainda contiver escapes de string JSON (\\n, \\r, etc.).

  // Corrige os escapes de string:
  if (typeof srtText === 'string') {
    srtText = srtText.replace(/\\n/g, '\n');
    srtText = srtText.replace(/\\r/g, '\r');
    srtText = srtText.replace(/\\t/g, ' '); 
    srtText = srtText.replace(/\\"/g, '"');
  } else {
    // Adiciona um tratamento para o caso do campo estar vazio ou não ser uma string
    console.error("O campo srtText não é uma string válida:", srtText);
    continue; // Pula para o próximo item
  }

  srtText = srtText.trim();
   
  // 3. CONVERSÃO E ANEXAÇÃO AO CAMPO BINÁRIO (item.binary)

  // Cria um Buffer (dados brutos) com a string SRT limpa.
  // Usamos 'utf8', essencial para legendas.
  const srtBuffer = Buffer.from(srtText, 'utf8');

  // 4. Adiciona o objeto binário à estrutura do n8n
  item.binary = item.binary || {}; 
  item.binary.srt_binary = {
    // Converte o Buffer em uma string base64 para ser serializada pelo n8n
    data: srtBuffer.toString('base64'), 
    mimeType: 'application/x-subrip', // MimeType padrão para SRT
    fileName: 'legenda.srt',
  };

  // Opcional: remove o campo de texto SRT se não for mais necessário.
  delete item.json.srt; 
}

return $input.all();

for (const item of $input.all()) {
  // 1. Acessa o campo que contém o texto com o JSON
  let jsonString = item.json.content.parts[0].text;

  // 2. Remove o prefixo e o sufixo do bloco de código Markdown
  //    (ex: ```json e ```)

  // Remove o prefixo (e espaços/quebras de linha ao redor)
  jsonString = jsonString.trim().replace(/^```json\s*/i, '');

  // Remove o sufixo (e espaços/quebras de linha ao redor)
  jsonString = jsonString.trim().replace(/```$/, '');

  // 3. Converte a string JSON para um objeto JSON
  try {
    const jsonObject = JSON.parse(jsonString);

    // 4. Adiciona o novo objeto JSON ao item de saída
    item.json.parsedJson = jsonObject;
  } catch (error) {
    // 5. Tratamento de erro: se a conversão falhar mesmo após a limpeza
    item.json.error = `Falha ao analisar JSON: ${error.message}`;
    item.json.rawText = jsonString; // Mantém o texto bruto para inspeção
  }
}

return $input.all();

// A função principal de um nó Code deve retornar o array de itens.
const outputItems = [];

// Itera sobre todos os itens de entrada (esperando 1 item neste caso)
for (const item of items) {

    // 1. Acessa o array 'srt' que contém os segmentos
    const srtSegments = item.json.parsedJson.srt;
    let srtFinalContent = '';

    if (srtSegments && Array.isArray(srtSegments)) {

        // 2. Constrói a String SRT (índice, timestamps, texto)
        srtSegments.forEach((segment, index) => {

            // Função para formatar o tempo de "MM:SS" para o formato SRT "HH:MM:SS,ms"
            const formatTime = (time) => {
                // Assumimos que a entrada é MM:SS. Converte para 00:MM:SS,000
                const [minutes, seconds] = time.split(':');
                const paddedMinutes = minutes.padStart(2, '0');
                const paddedSeconds = seconds.padStart(2, '0');
                return `00:${paddedMinutes}:${paddedSeconds},000`; 
            };

            const startTime = formatTime(segment.start);
            const endTime = formatTime(segment.end);

            // Constrói o bloco de legenda
            srtFinalContent += `${index + 1}\n`;
            srtFinalContent += `${startTime} --> ${endTime}\n`;
            srtFinalContent += `${segment.text}\n\n`;
        });

        // 3. Converte a string SRT finalizada para um Buffer binário
        const srtBuffer = Buffer.from(srtFinalContent.trim(), 'utf8');

        // 4. Cria o objeto de saída no formato que o n8n espera para dados binários.
        const newItem = {
            // Mantemos o JSON mínimo para dar nome ao arquivo no próximo nó
            json: {
                title: item.json.parsedJson.title 
            },
            binary: {
                // 'srtBinaryData' é o nome da propriedade binária que você usará no próximo nó.
                srtBinaryData: {
                    data: srtBuffer.toString('base64'), // O n8n armazena o Buffer como Base64
                    mimeType: 'text/srt',
                    // Sugestão de nome do arquivo
                    fileName: `${item.json.parsedJson.title}.srt`, 
                },
            },
        };
        outputItems.push(newItem);

    } else {
        console.error("ERRO: Array 'srt' não encontrado ou vazio.");
        outputItems.push({ json: { error: 'SRT_NOT_FOUND' }});
    }
}

return outputItems;

